const meals = items.map(i => i.json);

// sort by created_at DESC (latest first)
meals.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

return meals.map(m => ({ json: m }));

const index = $node["Code in JavaScript5"].json.index;
const newText = $node["Code in JavaScript5"].json.new_text;
const chatId = $node["Code in JavaScript5"].json.chat_id;

const meals = items.map(i => i.json);

// sort latest first
meals.sort((a, b) => new Date(b.created_at) - new Date(a.created_at));

if (!index || index < 1 || index > meals.length) {
  return [{
    json: {
      error: "Invalid index",
      chat_id: chatId
    }
  }];
}

const selectedMeal = meals[index - 1];

return [{
  json: {
    meal_id: selectedMeal.id,
    new_text: newText,
    chat_id: chatId,
    index
  }
}];

